	duration := nextTime.Sub(now)

	// Wait until the next execution time
	time.Sleep(duration)

	// Execute the cron job at 12 AM
	fmt.Println("Cron job executed at:", time.Now().Format("2006-01-02 15:04:05"))

	// Add your cron job logic here...

	// Your application can exit after running the cron job once a day
